+    @Benchmark
+    @OperationsPerInvocation(DEFAULT_X_RANGE)
+    public void calcDoubleConstDivisor() {
+        double sum = 0;
+        for (int i = 0; i < DEFAULT_X_RANGE; i++) {
+            double x = i;
+            sum += (13.0D * x * x * x) % 42.0D;
+        }
+        regressionValue = sum % 2 == 1;
+    }
+
+    @Benchmark
+    @OperationsPerInvocation(DEFAULT_X_RANGE)
+    public void calcDoubleConstDivisorSimple() {
+        double sum = 0;
+        for (int i = 0; i < DEFAULT_X_RANGE; i++) {
+            double x = i;
+            sum += x % 42.0D;
+        }
+        regressionValue = sum % 2 == 1;
+    }
